import React, { useEffect, useState } from "react";
import axios from "axios";
import mongoClient from "../api/mongoFrontend";

function NewsPage() {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchNews = async () => {
      try {
        // Prefer backend mongo proxy first
        try {
          const res = await axios.get('http://localhost:5000/mongo/news');
          console.debug('/mongo/news response status:', res.status, 'length:', Array.isArray(res.data) ? res.data.length : 'n/a');
          if (Array.isArray(res.data) && res.data.length) {
            console.debug('Using backend proxy /mongo/news with', res.data.length, 'articles');
            setArticles(res.data);
            setLoading(false);
            return;
          }
        } catch (e) {
          console.debug('Backend mongo proxy failed or returned empty, trying other sources:', e && e.message ? e.message : e);
        }

        // Fallback: try direct Atlas Data API via client helper (if configured)
        try {
          const docs = await mongoClient.getNewsDocuments({ collectionName: 'news' });
          console.debug('client Data API docs length:', Array.isArray(docs) ? docs.length : 'n/a');
          if (Array.isArray(docs) && docs.length) {
            const mapped = docs.map((d) => ({
              title: d.latest_headline || d.title || d.headline || '',
              summary: d.latest_article || d.summary || d.description || '',
              url: d.url || d.link || '#',
              source: d.source || d.source_name || 'News',
              published: d.updated_at || d.created_at || d.published || null,
            }));
            setArticles(mapped);
            setLoading(false);
            return;
          }
        } catch (err) {
          console.debug('Direct Mongo fetch failed, falling back to sample news API:', err && err.message ? err.message : err);
        }

        // Final fallback: previous sample feed endpoint
        const res2 = await axios.get("http://localhost:5000/market-news");
        setArticles(res2.data || []);
      } catch (err) {
        console.error(err);
        setArticles([]);
      } finally {
        setLoading(false);
      }
    };
    fetchNews();
  }, []);

  return (
    <div className="page-root">
      <h1>Market News</h1>
      <p>Latest headlines from Yahoo Finance</p>

      {loading && <p className="placeholder">Loading news...</p>}

      {!loading && !articles.length && (
        <p className="placeholder">No news available right now.</p>
      )}

      <div className="news-grid">
        {articles.map((article, idx) => (
          <article key={idx} className="news-card">
            <div className="news-meta">
              <span className="news-source">
                {article.source || "Yahoo Finance"}
              </span>
              {article.published && (
                <span className="news-time">{article.published}</span>
              )}
            </div>
            <h3>{article.title}</h3>
            {article.summary && (
              <p className="news-summary">{article.summary}</p>
            )}
            <a
              href={article.url}
              target="_blank"
              rel="noreferrer"
              className="news-link"
            >
              Read article →
            </a>
          </article>
        ))}
      </div>
    </div>
  );
}

export default NewsPage;
